INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (100, 'page', NULL, 'About', 'about', '{"version":"plumix.v2","blocks":[{"id":"b142","name":"core/rich-text","attrs":{"body":"<p>The Plumix Gazette is a demo publication built to show off the Plumix starter theme — a small, fast, content-first stack running on Cloudflare Workers.</p>"}},{"id":"b143","name":"core/rich-text","attrs":{"body":"<h2>What you''ll find here</h2>"}},{"id":"b144","name":"core/rich-text","attrs":{"body":"<p>Essays on travel, design, engineering, and food, plus the occasional interview. None of it is real; all of it is here to make the theme look like a living site.</p>"}}]}', NULL, 'published', 1, 0, '{}', 1777593600);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (101, 'page', 100, 'The Team', 'team', '{"version":"plumix.v2","blocks":[{"id":"b145","name":"core/rich-text","attrs":{"body":"<p>A masthead of exactly one: the editor, plus a generous amount of imagination.</p>"}}]}', NULL, 'published', 1, 0, '{}', 1777593600);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (102, 'page', NULL, 'Contact', 'contact', '{"version":"plumix.v2","blocks":[{"id":"b146","name":"core/rich-text","attrs":{"body":"<p>Reach the newsroom at <a href=\"mailto:hello@plumix.example\">hello@plumix.example</a>. We read everything and reply to most.</p>"}}]}', NULL, 'published', 1, 0, '{}', 1777593600);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (200, 'post', NULL, 'Typography & Elements: a theme test sheet', 'typography-and-elements-a-theme-test-sheet', '{"version":"plumix.v2","blocks":[{"id":"b1","name":"core/rich-text","attrs":{"body":"<p>This post is a reference for the theme''s typography. It exercises every element a writer reaches for, so the styles below double as a visual test sheet — in the spirit of WordPress''s theme-unit-test content.</p>"}},{"id":"b2","name":"core/rich-text","attrs":{"body":"<h2>Heading level two</h2>"}},{"id":"b3","name":"core/rich-text","attrs":{"body":"<p>A paragraph with <strong>bold</strong>, <em>italic</em>, <a href=\"/about\">a link</a>, <code>inline code</code>, and <mark>highlighted</mark> text. Lines wrap into a comfortable measure so longer passages stay readable across the column.</p>"}},{"id":"b4","name":"core/rich-text","attrs":{"body":"<h3>Heading level three</h3>"}},{"id":"b5","name":"core/rich-text","attrs":{"body":"<p>Unordered and ordered lists carry their own rhythm:</p><ul><li>Espresso, then water</li><li>Mise en place</li><li>Ship the smallest thing</li></ul><ol><li>Outline the idea</li><li>Draft without stopping</li><li>Edit ruthlessly</li></ol>"}},{"id":"b6","name":"core/rich-text","attrs":{"body":"<blockquote><p>Simplicity is the keynote of all true elegance. — Coco Chanel</p></blockquote>"}},{"id":"b7","name":"core/rich-text","attrs":{"body":"<h3>Code</h3>"}},{"id":"b8","name":"core/rich-text","attrs":{"body":"<p>Inline <code>const x = 1</code> and a fenced block:</p>"}},{"id":"b9","name":"core/code","attrs":{"language":"typescript","text":"export function greet(name: string): string {\n  return `Hello, ${name}!`;\n}"}},{"id":"b10","name":"core/separator","attrs":{}},{"id":"b11","name":"core/rich-text","attrs":{"body":"<h3>A table</h3>"}},{"id":"b12","name":"core/table","attrs":{"bordered":true,"rows":[{"id":"b13","name":"core/table-header-row","attrs":{"cells":[{"id":"b14","name":"core/table-header-cell","attrs":{"text":"City"}},{"id":"b15","name":"core/table-header-cell","attrs":{"text":"Country"}},{"id":"b16","name":"core/table-header-cell","attrs":{"text":"Known for"}}]}},{"id":"b17","name":"core/table-body-row","attrs":{"cells":[{"id":"b18","name":"core/table-cell","attrs":{"text":"Lisbon"}},{"id":"b19","name":"core/table-cell","attrs":{"text":"Portugal"}},{"id":"b20","name":"core/table-cell","attrs":{"text":"Light, tiles, trams"}}]}},{"id":"b21","name":"core/table-body-row","attrs":{"cells":[{"id":"b22","name":"core/table-cell","attrs":{"text":"Tokyo"}},{"id":"b23","name":"core/table-cell","attrs":{"text":"Japan"}},{"id":"b24","name":"core/table-cell","attrs":{"text":"Density, detail"}}]}},{"id":"b25","name":"core/table-body-row","attrs":{"cells":[{"id":"b26","name":"core/table-cell","attrs":{"text":"Oaxaca"}},{"id":"b27","name":"core/table-cell","attrs":{"text":"Mexico"}},{"id":"b28","name":"core/table-cell","attrs":{"text":"Mole, mezcal"}}]}}]}},{"id":"b29","name":"core/rich-text","attrs":{"body":"<h3>An image</h3>"}},{"id":"b30","name":"media/image","attrs":{"src":"https://picsum.photos/seed/plumix-elements-figure/1600/1000","alt":"A wide landscape","caption":"Figures carry an optional caption.","sizing":"full"}},{"id":"b31","name":"core/rich-text","attrs":{"body":"<blockquote><p>A plain blockquote, for when the quote block''s attribution isn''t needed.</p></blockquote><p>And a final paragraph to close the sheet.</p>"}}]}', 'There''s a particular pleasure in arriving somewhere with no plan and letting the day unfold.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-typography-and-elements-a-theme-test-sheet/1200/800","alt":"Typography & Elements: a theme test sheet","width":1200,"height":800}}', 1777593600);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (201, 'post', NULL, 'A Slow Morning in Lisbon', 'a-slow-morning-in-lisbon', '{"version":"plumix.v2","blocks":[{"id":"b32","name":"core/rich-text","attrs":{"body":"<p>Good design rarely announces itself; it just quietly makes the right thing easy.</p>"}},{"id":"b33","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b34","name":"core/rich-text","attrs":{"body":"<p>The constraint turned out to be the feature. Once we stopped fighting it, the interface got smaller, faster, and far easier to explain.</p>"}},{"id":"b35","name":"media/image","attrs":{"src":"https://picsum.photos/seed/plumix-post-1/1200/800","alt":"An illustrative photograph","caption":"","sizing":"full"}},{"id":"b36","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'Good design rarely announces itself; it just quietly makes the right thing easy.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-a-slow-morning-in-lisbon/1200/800","alt":"A Slow Morning in Lisbon","width":1200,"height":800}}', 1777334400);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (202, 'post', NULL, 'The Case for Smaller Interfaces', 'the-case-for-smaller-interfaces', '{"version":"plumix.v2","blocks":[{"id":"b37","name":"core/rich-text","attrs":{"body":"<p>The fastest code is the code that never runs — a lesson the platform keeps reteaching.</p>"}},{"id":"b38","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b39","name":"core/rich-text","attrs":{"body":"<p>Measurement first, opinions second. The profile disagreed with all of us, and it was right — the hot path wasn''t where anyone had guessed.</p>"}},{"id":"b40","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'The fastest code is the code that never runs — a lesson the platform keeps reteaching.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-the-case-for-smaller-interfaces/1200/800","alt":"The Case for Smaller Interfaces","width":1200,"height":800}}', 1777075200);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (203, 'post', NULL, 'Edge Rendering on Cloudflare Workers', 'edge-rendering-on-cloudflare-workers', '{"version":"plumix.v2","blocks":[{"id":"b41","name":"core/rich-text","attrs":{"body":"<p>A recipe is less a set of rules than a starting point you''re meant to argue with.</p>"}},{"id":"b42","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b43","name":"core/rich-text","attrs":{"body":"<p>Salt early, taste often, and trust your hands more than the clock. The best version was the one we made twice.</p>"}},{"id":"b44","name":"core/rich-text","attrs":{"body":"<blockquote><p>Travel far enough and you meet yourself. — David Mitchell</p></blockquote>"}},{"id":"b45","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'A recipe is less a set of rules than a starting point you''re meant to argue with.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-edge-rendering-on-cloudflare-workers/1200/800","alt":"Edge Rendering on Cloudflare Workers","width":1200,"height":800}}', 1776816000);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (204, 'post', NULL, 'A Weeknight Ragu Worth the Wait', 'a-weeknight-ragu-worth-the-wait', '{"version":"plumix.v2","blocks":[{"id":"b46","name":"core/rich-text","attrs":{"body":"<p>Every city keeps its real character in the streets the guidebooks skip.</p>"}},{"id":"b47","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b48","name":"core/rich-text","attrs":{"body":"<p>We walked until the map stopped meaning anything, which is usually when the trip actually begins. The light did most of the work; we just tried to keep up.</p>"}},{"id":"b49","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'Every city keeps its real character in the streets the guidebooks skip.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-a-weeknight-ragu-worth-the-wait/1200/800","alt":"A Weeknight Ragu Worth the Wait","width":1200,"height":800}}', 1776556800);
