INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (213, 'post', NULL, 'Less Chrome, More Content', 'less-chrome-more-content', '{"version":"plumix.v2","blocks":[{"id":"b87","name":"core/rich-text","attrs":{"body":"<p>A recipe is less a set of rules than a starting point you''re meant to argue with.</p>"}},{"id":"b88","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b89","name":"core/rich-text","attrs":{"body":"<p>The constraint turned out to be the feature. Once we stopped fighting it, the interface got smaller, faster, and far easier to explain.</p>"}},{"id":"b90","name":"media/image","attrs":{"src":"https://picsum.photos/seed/plumix-post-13/1200/800","alt":"An illustrative photograph","caption":"","sizing":"full"}},{"id":"b91","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'A recipe is less a set of rules than a starting point you''re meant to argue with.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-less-chrome-more-content/1200/800","alt":"Less Chrome, More Content","width":1200,"height":800}}', 1774224000);
