INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (215, 'post', NULL, 'Lisbon''s Miradouros, Ranked', 'lisbon-s-miradouros-ranked', '{"version":"plumix.v2","blocks":[{"id":"b96","name":"core/rich-text","attrs":{"body":"<p>There''s a particular pleasure in arriving somewhere with no plan and letting the day unfold.</p>"}},{"id":"b97","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b98","name":"core/rich-text","attrs":{"body":"<p>Salt early, taste often, and trust your hands more than the clock. The best version was the one we made twice.</p>"}},{"id":"b99","name":"core/rich-text","attrs":{"body":"<blockquote><p>Travel far enough and you meet yourself. — David Mitchell</p></blockquote>"}},{"id":"b100","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'There''s a particular pleasure in arriving somewhere with no plan and letting the day unfold.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-lisbon-s-miradouros-ranked/1200/800","alt":"Lisbon''s Miradouros, Ranked","width":1200,"height":800}}', 1773705600);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (216, 'post', NULL, 'The Quiet Power of Defaults', 'the-quiet-power-of-defaults', '{"version":"plumix.v2","blocks":[{"id":"b101","name":"core/rich-text","attrs":{"body":"<p>Good design rarely announces itself; it just quietly makes the right thing easy.</p>"}},{"id":"b102","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b103","name":"core/rich-text","attrs":{"body":"<p>We walked until the map stopped meaning anything, which is usually when the trip actually begins. The light did most of the work; we just tried to keep up.</p>"}},{"id":"b104","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'Good design rarely announces itself; it just quietly makes the right thing easy.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-the-quiet-power-of-defaults/1200/800","alt":"The Quiet Power of Defaults","width":1200,"height":800}}', 1773446400);
INSERT INTO entries (id, type, parent_id, title, slug, content, excerpt, status, author_id, sort_order, meta, published_at) VALUES (217, 'post', NULL, 'Shipping on a Friday (Carefully)', 'shipping-on-a-friday-carefully', '{"version":"plumix.v2","blocks":[{"id":"b105","name":"core/rich-text","attrs":{"body":"<p>The fastest code is the code that never runs — a lesson the platform keeps reteaching.</p>"}},{"id":"b106","name":"core/rich-text","attrs":{"body":"<h2>What we found</h2>"}},{"id":"b107","name":"core/rich-text","attrs":{"body":"<p>The constraint turned out to be the feature. Once we stopped fighting it, the interface got smaller, faster, and far easier to explain.</p>"}},{"id":"b108","name":"media/image","attrs":{"src":"https://picsum.photos/seed/plumix-post-17/1200/800","alt":"An illustrative photograph","caption":"","sizing":"full"}},{"id":"b109","name":"core/rich-text","attrs":{"body":"<p>We''ll pick this thread up again soon. Until then, the notes above should be enough to retrace our steps.</p>"}}]}', 'The fastest code is the code that never runs — a lesson the platform keeps reteaching.', 'published', 1, 0, '{"featuredImage":{"src":"https://picsum.photos/seed/plumix-cover-shipping-on-a-friday-carefully/1200/800","alt":"Shipping on a Friday (Carefully)","width":1200,"height":800}}', 1773187200);
